import pygame
import random
from enum import Enum
GRID_WIDTH = 10
GRID_HEIGHT = 20

class CellState(Enum):
    EMPTY = 0
    FILLED = 1

class Cell:
    __slots__ = ("state", "color")
    def __init__(self, state=CellState.EMPTY, color=None):
        self.state = state
        self.color = color

class Grid:
    def __init__(self, width=GRID_WIDTH, height=GRID_HEIGHT):
        self.width = width
        self.height = height
        self.cells = [[Cell() for _ in range(width)] for _ in range(height)]
    def is_inside(self, x, y):
        return 0 <= x < self.width and 0 <= y < self.height
    def get_cell(self, x, y):
        return self.cells[y][x]
    def set_cell(self, x, y, state, color=None):
        cell = self.cells[y][x]
        cell.state = state
        cell.color = color

# Rotation matrices
ROT_90  = ((0, -1), (1, 0))
ROT_180 = ((-1, 0), (0, -1))
ROT_270 = ((0, 1), (-1, 0))

def rotate_point(px, py, matrix):
    return px * matrix[0][0] + py * matrix[0][1], px * matrix[1][0] + py * matrix[1][1]

def generate_rotations(shape_coords):
    rotations = []
    current = shape_coords
    for matrix in (ROT_90, ROT_180, ROT_270):
        rotated = [rotate_point(x, y, matrix) for x, y in current]
        # normalize so min x,y is zero-based
        min_x = min(p[0] for p in rotated)
        min_y = min(p[1] for p in rotated)
        normalized = [(x - min_x, y - min_y) for x, y in rotated]
        rotations.append(normalized)
        current = rotated
    return rotations

# Tetromino base shapes in spawn orientation with origin at (0,0)
BASE_SHAPES = {
    'I': [(0,1),(1,1),(2,1),(3,1)],
    'J': [(0,0),(0,1),(1,1),(2,1)],
    'L': [(2,0),(0,1),(1,1),(2,1)],
    'O': [(0,0),(1,0),(0,1),(1,1)],
    'S': [(1,0),(2,0),(0,1),(1,1)],
    'T': [(1,0),(0,1),(1,1),(2,1)],
    'Z': [(0,0),(1,0),(1,1),(2,1)],
}

TETROMINO_COLORS = {
    'I': (0, 240, 240),
    'J': (0, 0, 240),
    'L': (240, 160, 0),
    'O': (240, 240, 0),
    'S': (0, 240, 0),
    'T': (160, 0, 240),
    'Z': (240, 0, 0),
}

class Tetromino:
    def __init__(self, shape_key):
        self.key = shape_key
        self.color = TETROMINO_COLORS[shape_key]
        base = BASE_SHAPES[shape_key]
        self.rotations = [base] + generate_rotations(base)
        self.rotation_index = 0
        self.blocks = list(self.rotations[self.rotation_index])
    def rotate(self, direction=1):
        self.rotation_index = (self.rotation_index + direction) % len(self.rotations)
        self.blocks = list(self.rotations[self.rotation_index])
    def get_blocks(self, offset_x=0, offset_y=0):
        return [(x + offset_x, y + offset_y) for x, y in self.blocks]

class GameLogic:
    def __init__(self, grid):
        self.grid = grid
        self.score = 0

    def find_matches(self):
        matches = []
        # Horizontal matches
        for y in range(self.grid.height):
            for x in range(self.grid.width - 2):
                color = self.grid.get_cell(x, y).color
                if color is not None and \
                   self.grid.get_cell(x + 1, y).color == color and \
                   self.grid.get_cell(x + 2, y).color == color:
                    match = [(x, y), (x + 1, y), (x + 2, y)]
                    i = 3
                    while x + i < self.grid.width and self.grid.get_cell(x + i, y).color == color:
                        match.append((x + i, y))
                        i += 1
                    if len(match) >= 3:
                        matches.append(match)

        # Vertical matches
        for x in range(self.grid.width):
            for y in range(self.grid.height - 2):
                color = self.grid.get_cell(x, y).color
                if color is not None and \
                   self.grid.get_cell(x, y + 1).color == color and \
                   self.grid.get_cell(x, y + 2).color == color:
                    match = [(x, y), (x, y + 1), (x, y + 2)]
                    i = 3
                    while y + i < self.grid.height and self.grid.get_cell(x, y + i).color == color:
                        match.append((x, y + i))
                        i += 1
                    if len(match) >= 3:
                        matches.append(match)
        return matches

    def clear_matches(self, matches):
        cleared_count = 0
        for match in matches:
            for x, y in match:
                if self.grid.get_cell(x, y).state == CellState.FILLED:
                    self.grid.set_cell(x, y, CellState.EMPTY, None)
                    cleared_count += 1
        return cleared_count

    def drop_gems(self):
        for x in range(self.grid.width):
            empty_pos = -1
            for y in range(self.grid.height):
                if self.grid.get_cell(x, y).state == CellState.EMPTY:
                    empty_pos = y
                    break
            if empty_pos != -1:
                for y in range(empty_pos + 1, self.grid.height):
                    if self.grid.get_cell(x, y).state == CellState.FILLED:
                        self.grid.set_cell(x, empty_pos, CellState.FILLED, self.grid.get_cell(x, y).color)
                        self.grid.set_cell(x, y, CellState.EMPTY, None)
                        empty_pos += 1

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.grid.height):
            is_full = all(self.grid.get_cell(x, y).state == CellState.FILLED for x in range(self.grid.width))
            if is_full:
                lines_cleared += 1
                # Clear the line
                for x in range(self.grid.width):
                    self.grid.set_cell(x, y, CellState.EMPTY, None)
                # Shift the above lines down
                for yy in range(y - 1, -1, -1):
                    for x in range(self.grid.width):
                        self.grid.set_cell(x, yy + 1, self.grid.get_cell(x, yy).state, self.grid.get_cell(x, yy).color)
                # Clear the top line
                for x in range(self.grid.width):
                    self.grid.set_cell(x, 0, CellState.EMPTY, None)
        return lines_cleared

    def resolve_chains(self):
        chain_reaction = True
        total_cleared = 0
        chain_multiplier = 1
        while chain_reaction:
            matches = self.find_matches()
            lines_cleared = self.clear_lines()

            if matches or lines_cleared > 0:
                cleared_count = self.clear_matches(matches)
                total_cleared += cleared_count + lines_cleared * self.grid.width

                self.drop_gems()

                self.score += (cleared_count + lines_cleared * self.grid.width) * 10 * chain_multiplier
                chain_multiplier += 0.5 # increase chain multiplier
            else:
                chain_reaction = False
        return total_cleared

    def update_score(self, cleared):
        self.score += cleared * 10  # Example scoring
