SPAWN_Y = 0
PREVIEW_SIZE = 4
PREVIEW_POS = (450, 100)

class GameState(Enum):
    ACTIVE = 0
    PAUSED = 1
    GAME_OVER = 2

class TetrisJeweled:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris Jeweled")
        self.clock = pygame.time.Clock()
        self.grid = Grid()
        self.current_tetromino = self.new_tetromino()
        self.next_tetromino = self.new_tetromino()
        self.tetromino_x = SPAWN_X
        self.tetromino_y = SPAWN_Y
        self.game_state = GameState.ACTIVE
        self.score = 0
        self.drop_speed = 500 # milliseconds
        self.last_drop_time = pygame.time.get_ticks()
        self.animation_frames = 6
        self.animation_timer = 0

    def new_tetromino(self):
        return Tetromino(random.choice(list(BASE_SHAPES.keys())))

    def run(self):
        running = True
        while running:
            delta_time = self.clock.tick(60) / 1000.0
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT and self.game_state == GameState.ACTIVE:
                        self.move_tetromino(-1, 0)
                    if event.key == pygame.K_RIGHT and self.game_state == GameState.ACTIVE:
                        self.move_tetromino(1, 0)
                    if event.key == pygame.K_DOWN and self.game_state == GameState.ACTIVE:
                        self.move_tetromino(0, 1)
                    if event.key == pygame.K_UP and self.game_state == GameState.ACTIVE:
                        self.rotate_tetromino()
                    if event.key == pygame.K_SPACE and self.game_state == GameState.ACTIVE:
                        self.drop_tetromino()
                    if event.key == pygame.K_p:
                        if self.game_state == GameState.ACTIVE:
                            self.game_state = GameState.PAUSED
                        elif self.game_state == GameState.PAUSED:
                            self.game_state = GameState.ACTIVE

            if self.game_state == GameState.ACTIVE:
                self.update(delta_time)
            self.render()
            pygame.display.flip()

        pygame.quit()

    def update(self, delta_time):
        time_now = pygame.time.get_ticks()
        if time_now - self.last_drop_time > self.drop_speed:
            self.move_tetromino(0, 1)
            self.last_drop_time = time_now

        if self.animation_timer > 0:
            self.animation_timer -= 1

    def move_tetromino(self, dx, dy):
        new_x = self.tetromino_x + dx
        new_y = self.tetromino_y + dy
        if self.is_valid_position(new_x, new_y, self.current_tetromino):
            self.tetromino_x = new_x
            self.tetromino_y = new_y
        elif dy != 0:  # Attempting to move down and collision occurred
            self.lock_tetromino()

    def rotate_tetromino(self):
        original_rotation_index = self.current_tetromino.rotation_index
        self.current_tetromino.rotate()
        if not self.is_valid_position(self.tetromino_x, self.tetromino_y, self.current_tetromino):
            # Revert rotation if the new position is invalid
            self.current_tetromino.rotation_index = original_rotation_index
            self.current_tetromino.blocks = list(self.current_tetromino.rotations[original_rotation_index])

    def drop_tetromino(self):
        while self.is_valid_position(self.tetromino_x, self.tetromino_y + 1, self.current_tetromino):
            self.tetromino_y += 1
        self.lock_tetromino()

    def is_valid_position(self, x, y, tetromino):
        for block_x, block_y in tetromino.get_blocks(x, y):
            if not self.grid.is_inside(block_x, block_y) or self.grid.get_cell(block_x, block_y).state == CellState.FILLED:
                return False
        return True

    def lock_tetromino(self):
        for block_x, block_y in self.current_tetromino.get_blocks(self.tetromino_x, self.tetromino_y):
            self.grid.set_cell(block_x, block_y, CellState.FILLED, self.current_tetromino.color)
